evaluators.evaluation_logic:
const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const lists = JSON.parse(localStorage.getItem('project_lists') || '[]');
const items = JSON.parse(localStorage.getItem('project_list_items') || '[]');

// Find qualifying projects by criteria
const qualifyingProjects = projects.filter(p => {
  if (p.topic !== 'freshwater_biodiversity') return false;
  if (p.region !== 'africa') return false;
  if (p.status !== 'ongoing') return false;
  if (typeof p.start_year !== 'number' || p.start_year < 2018 || p.start_year > 2022) return false;
  if (typeof p.total_funding !== 'number' || p.total_funding < 1000000) return false;
  return true;
});

qualifyingProjects.sort((a, b) => (b.total_funding || 0) - (a.total_funding || 0));
const top3 = qualifyingProjects.slice(0, 3);
const top3Ids = top3.map(p => p.id);

// For each comparison list, see how many of the top3 it contains
let maxMatchCount = 0;
lists.forEach(list => {
  if (list.list_type !== 'comparison') return;
  const listProjectIds = items
    .filter(it => it.project_list_id === list.id)
    .map(it => it.project_id);
  const count = top3Ids.filter(id => listProjectIds.includes(id)).length;
  if (count > maxMatchCount) maxMatchCount = count;
});

// Checkpoints: how many of the top 3 highest-funded qualifying projects are saved together
[1, 2, 3].forEach((n, index) => {
  const weight = index === 0 ? 0.34 : 0.33; // 0.34 + 0.33 + 0.33 = 1.0
  checkpoints.push({ passed: maxMatchCount >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const subs = JSON.parse(localStorage.getItem('project_update_subscriptions') || '[]');

// Qualifying coastal restoration projects in South America with fieldwork in 2024
const qualifyingProjectIds = projects
  .filter(p => {
    if (p.topic !== 'coastal_restoration') return false;
    if (p.region !== 'south_america') return false;
    if (!Array.isArray(p.fieldwork_years) || !p.fieldwork_years.includes(2024)) return false;
    return true;
  })
  .map(p => p.id);

const qualifyingSubs = subs.filter(s =>
  qualifyingProjectIds.includes(s.project_id) &&
  s.email_updates_enabled === true
);

const qualifyingSubsCorrectEmail = qualifyingSubs.filter(s =>
  s.email === 'coastal.observer@example.org'
);

// CP1 (0.6): Subscription with email updates enabled to a qualifying project
checkpoints.push({
  passed: qualifyingSubs.length >= 1,
  weight: 0.6
});

// CP2 (0.4): That subscription used the expected email address
checkpoints.push({
  passed: qualifyingSubsCorrectEmail.length >= 1,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const pubs = JSON.parse(localStorage.getItem('publications') || '[]');
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Qualifying peer-reviewed PM2.5 urban air quality articles, 2019-2023
const qualifyingPubs = pubs.filter(p => {
  if (p.type !== 'peer_reviewed_article') return false;
  if (typeof p.publication_year !== 'number' || p.publication_year < 2019 || p.publication_year > 2023) return false;
  const topic = (p.topic || '').toLowerCase();
  return topic.includes('pm2.5') && topic.includes('urban');
});

qualifyingPubs.sort((a, b) => (b.citation_count || 0) - (a.citation_count || 0));
const topFiveIds = qualifyingPubs.slice(0, 5).map(p => p.id);

// Find reading lists named exactly 'Urban Air Quality'
const uaLists = lists.filter(l => (l.name || '').toLowerCase() === 'urban air quality');

let maxMatchCount = 0;
uaLists.forEach(list => {
  const listPubIds = items
    .filter(it => it.reading_list_id === list.id)
    .map(it => it.publication_id);
  const count = topFiveIds.filter(id => listPubIds.includes(id)).length;
  if (count > maxMatchCount) maxMatchCount = count;
});

// Checkpoints: how many of the top 5 are present in an 'Urban Air Quality' list
[1, 2, 3, 4, 5].forEach(n => {
  checkpoints.push({ passed: maxMatchCount >= n, weight: 0.2 });
});

return check points.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

const startMin = new Date('2025-01-01T00:00:00Z');
const startMax = new Date('2025-06-30T23:59:59Z');

// Qualifying climate adaptation webinars in H1 2025
const qualifyingEvents = events.filter(e => {
  if (e.event_type !== 'webinar') return false;
  if (e.topic !== 'climate_adaptation') return false;
  const d = e.start_datetime ? new Date(e.start_datetime) : null;
  if (!d || isNaN(d.getTime())) return false;
  return d >= startMin && d <= startMax;
});

// Count how many qualifying events have a matching registration with schedule added
const registeredAndScheduledCount = qualifyingEvents.reduce((count, e) => {
  const hasReg = regs.some(r =>
    r.event_id === e.id &&
    r.registration_status !== 'cancelled' &&
    r.registrant_name === 'Alex Rivera' &&
    r.registrant_email === 'alex.rivera@example.org' &&
    r.added_to_schedule === true
  );
  return count + (hasReg ? 1 : 0);
}, 0);

// CP1 (0.5): At least one qualifying webinar registered and added to schedule with correct details
checkpoints.push({
  passed: registeredAndScheduledCount >= 1,
  weight: 0.5
});

// CP2 (0.5): Both qualifying webinars registered and added to schedule with correct details
checkpoints.push({
  passed: registeredAndScheduledCount >= 2,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const datasets = JSON.parse(localStorage.getItem('datasets') || '[]');
const queues = JSON.parse(localStorage.getItem('download_queue') || '[]');
const allItems = JSON.parse(localStorage.getItem('download_queue_items') || '[]');
const currentId = localStorage.getItem('download_queue_current_id') || (queues[0] && queues[0].id) || null;
const queueItems = currentId ? allItems.filter(it => it.download_queue_id === currentId) : [];
const queueDatasetIds = queueItems.map(it => it.dataset_id);

const zipInfo = JSON.parse(localStorage.getItem('task5_zipDownload') || 'null');

// Qualifying datasets by criteria
const qualifyingDatasets = datasets.filter(d => {
  if (d.topic !== 'deforestation') return false;
  if (d.region !== 'southeast_asia') return false;
  if (!['cc_by', 'cc0'].includes(d.license)) return false;
  const primary = d.primary_format || null;
  const formats = Array.isArray(d.file_formats) ? d.file_formats : [];
  return primary === 'csv' || formats.includes('csv');
});

qualifyingDatasets.sort((a, b) => {
  const ta = a.last_updated ? new Date(a.last_updated).getTime() : 0;
  const tb = b.last_updated ? new Date(b.last_updated).getTime() : 0;
  return tb - ta; // newest first
});

const top2Ids = qualifyingDatasets.slice(0, 2).map(d => d.id);

const inQueueTop = top2Ids.filter(id => queueDatasetIds.includes(id));
const inZipTop = top2Ids.filter(id => zipInfo && Array.isArray(zipInfo.dataset_ids) && zipInfo.dataset_ids.includes(id));

// CP1 (0.2): At least one of the top 2 qualifying datasets is both in the queue and listed in the prepared ZIP
checkpoints.push({
  passed: inQueueTop.length >= 1 && inZipTop.length >= 1,
  weight: 0.2
});

// CP2 (0.4): Both top 2 qualifying datasets are in the queue and listed in the prepared ZIP
checkpoints.push({
  passed: inQueueTop.length >= 2 && inZipTop.length >= 2,
  weight: 0.4
});

// CP3 (0.4): ZIP preparation metadata is consistent with the current download queue
let zipConsistent = false;
if (zipInfo && zipInfo.prepared && typeof zipInfo.file_count === 'number' && Array.isArray(zipInfo.dataset_ids)) {
  const fileCountMatches = zipInfo.file_count === zipInfo.dataset_ids.length && zipInfo.file_count === queueDatasetIds.length && zipInfo.file_count >= 2;
  if (fileCountMatches) {
    const setA = new Set(zipInfo.dataset_ids);
    const setB = new Set(queueDatasetIds);
    if (setA.size === setB.size) {
      zipConsistent = true;
      setA.forEach(id => {
        if (!setB.has(id)) zipConsistent = false;
      });
    }
  }
}

checkpoints.push({
  passed: zipConsistent,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

// Qualifying medium-risk water quality projects with community engagement
const qualifying = projects.filter(p => {
  if (p.topic !== 'water_quality') return false;
  if (p.risk_level !== 'medium') return false;
  if (p.has_community_engagement !== true) return false;
  return true;
});

qualifying.sort((a, b) => {
  const ta = a.start_date ? new Date(a.start_date).getTime() : 0;
  const tb = b.start_date ? new Date(b.start_date).getTime() : 0;
  return tb - ta; // newest first
});

const targetProject = qualifying.length >= 2 ? qualifying[1] : null;

const targetMessages = targetProject
  ? messages.filter(m => m.project_id === targetProject.id)
  : [];

const expectedBody = 'I am interested in joining the volunteer mailing list for this project, especially for activities planned between June and December. Please add me to any community outreach announcements.';

// CP1 (0.4): Any sent message to the correct target project with non-empty fields
const basicCorrect = targetMessages.some(m =>
  m.status === 'sent' &&
  m.sender_name &&
  m.sender_email &&
  m.message_body
);

checkpoints.push({
  passed: !!basicCorrect,
  weight: 0.4
});

// CP2 (0.6): Message to the correct project with the exact expected name, email, and body
const fullyCorrect = targetMessages.some(m =>
  m.status === 'sent' &&
  m.sender_name === 'Jordan Lee' &&
  m.sender_email === 'jordan.lee@example.net' &&
  m.message_body === expectedBody
);

checkpoints.push({
  passed: !!fullyCorrect,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const notes = JSON.parse(localStorage.getItem('notes') || '[]');

// Qualifying microplastics projects by criteria
const qualifyingProjects = projects.filter(p => {
  if (p.topic !== 'microplastics') return false;
  if (p.status !== 'ongoing') return false;
  if (typeof p.total_funding !== 'number' || p.total_funding > 500000) return false;
  if (typeof p.team_size !== 'number' || p.team_size > 10) return false;
  return true;
});

const qualifyingIds = new Set(qualifyingProjects.map(p => p.id));

const expectedBody = 'Follow up with this PI about potential collaboration on microplastics research methods.';

// Notes linked to qualifying projects
const candidateNotes = notes.filter(n => qualifyingIds.has(n.related_project_id));

// Notes with correct title and body
const correctTitleBodyNotes = candidateNotes.filter(n =>
  (n.title || '').toLowerCase() === 'collaboration ideas' &&
  n.body === expectedBody
);

// Notes with matching PI contact fields
const fullyCorrectNotes = correctTitleBodyNotes.filter(n => {
  const proj = projects.find(p => p.id === n.related_project_id);
  if (!proj) return false;
  const piNameMatches = (n.related_pi_name || '') === (proj.primary_investigator_name || '');
  const piEmailMatches = (n.related_pi_email || '') === (proj.primary_investigator_email || '');
  return piNameMatches && piEmailMatches;
});

// CP1 (0.6): At least one note linked to a qualifying project with correct title and body
checkpoints.push({
  passed: correctTitleBodyNotes.length >= 1,
  weight: 0.6
});

// CP2 (0.4): That note also has PI name and email matching the project
checkpoints.push({
  passed: fullyCorrectNotes.length >= 1,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const briefings = JSON.parse(localStorage.getItem('briefings') || '[]');

// Qualifying completed renewable energy projects in Europe
const qualifying = projects.filter(p => {
  if (p.topic !== 'renewable_energy') return false;
  if (p.region !== 'europe') return false;
  if (p.status !== 'completed') return false;
  return true;
});

qualifying.sort((a, b) => {
  const ta = a.end_date ? new Date(a.end_date).getTime() : 0;
  const tb = b.end_date ? new Date(b.end_date).getTime() : 0;
  return tb - ta; // most recent end date first
});

const firstTwo = qualifying.slice(0, 2);
let selectedProject = null;

if (firstTwo.length === 1) {
  selectedProject = firstTwo[0];
} else if (firstTwo.length === 2) {
  const dur1 = typeof firstTwo[0].duration_months === 'number' ? firstTwo[0].duration_months : 0;
  const dur2 = typeof firstTwo[1].duration_months === 'number' ? firstTwo[1].duration_months : 0;
  selectedProject = dur1 >= dur2 ? firstTwo[0] : firstTwo[1];
}

const selectedBriefings = selectedProject
  ? briefings.filter(b => b.project_id === selectedProject.id)
  : [];

const hasAnyBriefing = selectedBriefings.length > 0;

const hasAllSections = selectedBriefings.some(b => {
  const sections = Array.isArray(b.included_sections) ? b.included_sections : [];
  return sections.includes('objectives') && sections.includes('methods') && sections.includes('key_outcomes');
});

// CP1 (0.4): A briefing exists for the correctly selected project
checkpoints.push({
  passed: !!hasAnyBriefing,
  weight: 0.4
});

// CP2 (0.6): That briefing includes objectives, methods, and key outcomes sections
checkpoints.push({
  passed: !!hasAllSections,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
